INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-1057938728087518129', '人工智能', '独家对谈｜缘启智慧CEO邓江，一个80后银行码农出身的AI医疗创业者', 'https://36kr.com/p/3786252394945795?f=rss', '36kr', '2026-04-28', '\n  图源：公众号「职场Bonus」（ID：ZhiChangHongLi）\n  今年三月，《职场Bonus》报道了前百川智能商业化合伙人邓江加入北电数智</', '该事件值得关注。', 'other', 0.5, '2026-04-29 08:43:23', '2026-04-29 08:43:22', '2026-04-29 08:43:30', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-1236556567973276339', '人工智能', 'OpenAI和Anthropic就高阶网络安全AI模型与美国众议院委员会展开会晤', 'https://36kr.com/newsflashes/3787141617490945?f=rss', '36kr', '2026-04-29', 'OpenAI与Anthropic向美国众议院国土安全委员会工作人员，专项汇报了旗下具备网络攻防能力的新一代AI模型，以及该类技术对网络安全产生的各类影响。这是美国立法机构首次就新型AI模型引发的网络威胁，与两大AI巨头开展专项沟通的会议之一，重点涵盖防护薄弱��关键基础设施领域面临的安全风险。委员会一名助理证实，两家企业于上周四，以两场独立非公开机密会议形式，向国会工作人员进行专项简报。（新浪财经', '技术突破可能带来新的商业机会。', 'tech', 0.5, '2026-04-29 08:43:23', '2026-04-29 08:43:22', '2026-04-29 08:43:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-1595674914745393717', '新能源汽车', '加州海岸委员会向马斯克和SpaceX致歉，承诺未来监管决策不考虑政治因素', 'https://36kr.com/newsflashes/3787173820619785?f=rss', '36kr', '2026-04-29', '根据电动汽车分析师索耶·梅瑞特在X上分享的消息，美国加州海岸委员会已向加州海岸委员会已向埃隆·马斯克和 SpaceX公司正式道歉，并承诺未来在监管决策中不会考虑政治观点或言论。马斯克转发了梅瑞特的这篇帖子。梅瑞特评论称：“这份文件意味着 SpaceX和加州海岸委员会已就其联邦诉讼达成和解，并为SpaceX未来的猎鹰9号火箭发射提供了长期的监管清晰度。”（新浪财经）', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:16:54', '2026-04-29 10:16:53', '2026-04-29 10:16:53', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-1626320359432833417', '人工智能', '「寻明生科」完成3500万美元A+轮融资，首个抗体药物即将进入临床｜36氪首发', 'https://36kr.com/p/3784480103455748?f=rss', '36kr', '2026-04-28', '文｜胡香赟\n  编辑｜海若镜\n  36氪获悉，寻明生科（Aureka Biotechnologies）近期已完成3500万美元A+轮融资。本轮融资由红杉中国领投，经纬创投、博远资本跟投，老股东五源资本、启明创投、纽尔利资本等持续加注。\n  去年底，寻明生科就曾获得一笔数千万美元的A轮融资。截至目前，公司A轮次融资的累计金额已接近1亿美元。\n  寻明生科方面表示，本轮募集资金将用于推动自研创新功能抗', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 08:43:23', '2026-04-29 08:43:22', '2026-04-29 08:43:30', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-1652050210849738767', '人工智能', '独家对谈｜兴辉时代创始人高兴辉，90后小镇女孩离开教培大厂，三年创造2亿GMV的倔强人生', 'https://36kr.com/p/3786265971334150?f=rss', '36kr', '2026-04-29', '\n  图源：公众号「职场Bonus」（ID：ZhiChangHongLi）\n  兴辉，山西人，三次面试新东方才被录用。\n  转战高途教育后，她与另外三名男同事一同被封为公司的“三王一后”。\n  如今她已自己创业近三年。带着对教培行业发展水温的好奇，我们拜访了兴辉的公司。\n  一进门，同事们喊她“辉哥”——这与她外表精瘦，笑起来有虎牙的形象相比，实在让人难以关联。\n  但当我们听到在整个教培行业最为', '人事变动可能影响公司战略方向。', 'person', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 09:24:25', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-1661577416956538012', '人工智能', '独家对谈｜兴辉时代创始人高兴辉，90后小镇女孩离开教培大厂，三年创造2亿GMV的倔强人生', 'https://36kr.com/p/3786265971334150?f=rss', '36kr', '2026-04-29', '\n  图源：公众号「职场Bonus」（ID：ZhiChangHongLi）\n  兴辉，山西人，三次面试新东方才被录用。\n  转战高途教育后，她与另外三名男同事一同被封为公司的“三王一后”。\n  如今她已自己创业近三年。带着对教培行业发展水温的好奇，我们拜访了兴辉的公司。\n  一进门，同事们喊她“辉哥”——这与她外表精瘦，笑起来有虎牙的形象相比，实在让人难以关联。\n  但当我们听到在整个教培行业最为', '人事变动可能影响公司战略方向。', 'person', 0.5, '2026-04-29 09:00:30', '2026-04-29 09:00:29', '2026-04-29 09:00:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-1665119331112331829', '人工智能', '欧盟《数字市场法》监管范围拟扩大至云服务与AI领域', 'https://36kr.com/newsflashes/3787149562682627?f=rss', '36kr', '2026-04-29', '欧盟监管机构周二表示，计划将其旨在遏制大型科技公司权力的里程碑式法规《数字市场法》的监管重点转向云服务和人工智能领域。此举旨在促进公平竞争，此前该法已在其他数字领域取得了积极成效。（新浪财经）', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:00:30', '2026-04-29 09:00:30', '2026-04-29 09:00:30', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-1849975534781054135', '机器人', '业内人士：厄尔尼诺现象最早或年中出现，关注农产品市场结构性机遇', 'https://36kr.com/newsflashes/3787140499184640?f=rss', '36kr', '2026-04-29', '日前，世界气象组织等多家权威机构联合预警，厄尔尼诺现象可能最早于2026年5月至7月正式登场，且大概率发展为中等及以上强度并持续至年底。这一气候异常现象将重构全球降水与气温分布模式，对全球农业生产造成显著冲击。业内人士表示，当前农产品期货价格已受市场预期带动提前异动，随着厄尔尼诺现象预期逐步兑现，农产品市场的结构性机遇将进一步释放，可关注天然橡胶、棕榈油以及白糖等品种多头机会。（中证网）', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 08:43:30', '2026-04-29 08:43:29', '2026-04-29 08:43:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-1955381614118926754', '元宇宙', '氪星晚报｜我国最大规模AI4S集群接入全国一体化算力网；亚马逊低地轨道卫星计划又一批卫星发射升空；我国首款正向设计自转旋翼机完成首飞', 'https://36kr.com/p/3786324189027332?f=rss', '36kr', '2026-04-28', '大公司：\n  拒买新闻就交税，澳洲拟向科技巨头征约2%营收税\n  澳大利亚政府公布法案草案，拟对Meta、谷歌等科技巨头征收新税，除非这些平台自愿与当地新闻机构签署付费协议，以应对传统媒体在数码平台冲击下面临的生存压力。据报道，根据拟议的新法律安排，这些大型数码平台须就分享本地媒体新闻内容所带来的平台流量，向出版商提供经济补偿。澳洲总理阿尔巴尼斯表明，政府将给予Meta、谷歌等公司机会，与本地新闻', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:54:41', '2026-04-29 10:54:41', '2026-04-29 10:54:50', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-2149965965851426622', '人工智能', '未岚大陆第100万台智能割草机器人下线，马来西亚产线已完成、全面启动生产｜最前线', 'https://36kr.com/p/3784879395134465?f=rss', '36kr', '2026-04-27', '作者｜黄楠\n  编辑｜袁斯来\n  近日，智能割草机器人公司未岚大陆第100万台智能割草机器人下线仪式在其常州研发生产基地举办。未岚大陆CEO任冠佼、总裁兼CTO陈子冲、德国莱茵TÜV电子电气产品服务全球高级副总裁郝福来（Frank Holzmann）等出席仪式。\n  在割草机器人赛道竞争白热化的节点，百万台是对技术路线选择、供应链韧性与全球化布局的一次系统验证。从2021年发布第一款无边界智能割草', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 08:45:58', '2026-04-29 08:45:57', '2026-04-29 08:46:04', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-2274849631029737873', '人工智能', '苹果计划在iOS 27中借助AI对照片编辑功能进行全面升级', 'https://36kr.com/newsflashes/3787148066593798?f=rss', '36kr', '2026-04-29', '当地时间4月28日，据报道，苹果公司正计划对iPhone、iPad和Mac的内置照片编辑功能进行重大升级，并深度依托人工智能技术，以此缩小与安卓设备的竞争差距。据知情人士透露，该公司正在为计划于今年秋季发布的iOS 27、iPadOS 27和macOS 27开发一套由Apple Intelligence平台驱动的新工具套件。这些功能将允许用户利用设备端的AI模型对图片进行扩展、增强和重新构图。知情', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 08:45:58', '2026-04-29 08:45:57', '2026-04-29 08:45:57', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-2298154556275635310', '人工智能', '氪星晚报｜我国最大规模AI4S集群接入全国一体化算力网；亚马逊低地轨道卫星计划又一批卫星发射升空；我国首款正向设计自转旋翼机完成首飞', 'https://36kr.com/p/3786324189027332?f=rss', '36kr', '2026-04-28', '大公司：\n  拒买新闻就交税，澳洲拟向科技巨头征约2%营收税\n  澳大利亚政府公布法案草案，拟对Meta、谷歌等科技巨头征收新税，除非这些平台自愿与当地新闻机构签署付费协议，以应对传统媒体在数码平台冲击下面临的生存压力。据报道，根据拟议的新法律安排，这些大型数码平台须就分享本地媒体新闻内容所带来的平台流量，向出版商提供经济补偿。澳洲总理阿尔巴尼斯表明，政府将给予Meta、谷歌等公司机会，与本地新闻', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 09:24:25', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-2397448557773860335', '人工智能', '8点1氪丨百度废除字母职级标签；Meta被曝准备撤销对Manus收购；张雪称曾拒绝了半个亿的商务合作', 'https://36kr.com/p/3787150633065728?f=rss', '36kr', '2026-04-29', '今日热点导览\n  阿联酋宣布将退出欧佩克及“欧佩克+”\n  比亚迪宣布5月1日起涨价\n  五粮液：延期披露年报、一季报\n  普通本科高校上新38种专业\n  全马“破2”跑鞋被炒至近2万元\n  韩股市值超越英国，成为全球第八大股市\n  TOP3大新闻\n  百度职级体系大调整：字母标签改为5级至12级数字职级体系\n  4月28日，据《科创板日报》，百度发布全员信，通知职级体系大调整，其将中管层以下的专', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 08:45:58', '2026-04-29 08:45:57', '2026-04-29 08:46:04', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-2438454417745967933', '人工智能', '氪星晚报｜我国最大规模AI4S集群接入全国一体化算力网；亚马逊低地轨道卫星计划又一批卫星发射升空；我国首款正向设计自转旋翼机完成首飞', 'https://36kr.com/p/3786324189027332?f=rss', '36kr', '2026-04-28', '大公司：\n  拒买新闻就交税，澳洲拟向科技巨头征约2%营收税\n  澳大利亚政府公布法案草案，拟对Meta、谷歌等科技巨头征收新税，除非这些平台自愿与当地新闻机构签署付费协议，以应对传统媒体在数码平台冲击下面临的生存压力。据报道，根据拟议的新法律安排，这些大型数码平台须就分享本地媒体新闻内容所带来的平台流量，向出版商提供经济补偿。澳洲总理阿尔巴尼斯表明，政府将给予Meta、谷歌等公司机会，与本地新闻', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 08:45:58', '2026-04-29 08:45:57', '2026-04-29 08:46:04', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-2566585630779164693', '人工智能', '8点1氪丨百度废除字母职级标签；Meta被曝准备撤销对Manus收购；张雪称曾拒绝了半个亿的商务合作', 'https://36kr.com/p/3787150633065728?f=rss', '36kr', '2026-04-29', '今日热点导览\n  阿联酋宣布将退出欧佩克及“欧佩克+”\n  比亚迪宣布5月1日起涨价\n  五粮液：延期披露年报、一季报\n  普通本科高校上新38种专业\n  全马“破2”跑鞋被炒至近2万元\n  韩股市值超越英国，成为全球第八大股市\n  TOP3大新闻\n  百度职级体系大调整：字母标签改为5级至12级数字职级体系\n  4月28日，据《科创板日报》，百度发布全员信，通知职级体系大调整，其将中管层以下的专', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 08:43:23', '2026-04-29 08:43:22', '2026-04-29 08:43:30', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-2576681638042601370', '新能源汽车', '恒指开盘涨0.63%，恒生科技指数涨1.07%', 'https://36kr.com/newsflashes/3787224093023490?f=rss', '36kr', '2026-04-29', '36氪获悉，恒指开盘涨0.63%，恒生科技指数涨1.07%；科技、汽车股走强，蔚来、京东健康涨超4%，理想汽车涨超3%，小鹏集团、哔哩哔哩涨超2%；有色金属、煤炭板块调整，五矿资源、中煤能源跌超1%；新股商米科技高开292.20%。', '该事件值得关注。', 'other', 0.5, '2026-04-29 10:55:23', '2026-04-29 10:55:23', '2026-04-29 10:55:23', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-2646654911214962602', '人工智能', '比博斯特完成超10亿元B轮融资，智能底盘三轴产品全覆盖｜36氪独家', 'https://36kr.com/p/3740907027054600?f=rss', '36kr', '2026-04-29', '36氪独家获悉，智能底盘企业比博斯特近日完成B+轮融资，由浙江省新能源汽车产业基金领投，顺创产投、杭资直投基金等联合投资。企业B+轮融资超7亿元，B轮系列融资总额已超10亿元。本轮融资将用于已有产品的规模化增长及前沿产品的开发。\n  比博斯特成立于2021年，其股东不仅包括主机厂蔚来，还涵盖恒隆、保隆等汽车底盘供应链头部企业。2025年，曾在底盘巨头采埃孚担任高管的巫子平、郁炜陆续加入比博斯特，出', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:33:14', '2026-04-29 09:33:13', '2026-04-29 09:33:13', 0.5);
