INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-9079278678269471108', '机器人', '港股IPO热潮中的中资券商：保荐数量与市场份额领跑', 'https://36kr.com/newsflashes/3787179604679683?f=rss', '36kr', '2026-04-29', '2025年港股IPO市场强势复苏，全年新股上市数量与募资规模双双攀升，募资总额接近2900亿港元，时隔4年重回全球榜首。进入2026年，已有47家企业成功赴港上市，合计募资接近1400亿港元，且当前排队企业多达434家。综合来看，港股IPO业务呈现三大鲜明特征：A股企业赴港上市持续升温，硬科技与生物医药成为主力赛道；中资券商保荐数量与市场份额大幅领先，头部机构加速布局海外投行生态；项目储备持续饱满', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:24:25', '2026-04-29 09:24:25', '2026-04-29 09:24:27', 0.5);
