INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_3448294106752208151', '人工智能', '欧盟《数字市场法》监管范围拟扩大至云服务与AI领域', 'https://36kr.com/newsflashes/3787149562682627?f=rss', '36kr', '2026-04-29', '欧盟监管机构周二表示，计划将其旨在遏制大型科技公司权力的里程碑式法规《数字市场法》的监管重点转向云服务和人工智能领域。此举旨在促进公平竞争，此前该法已在其他数字领域取得了积极成效。（新浪财经）', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 08:45:58', '2026-04-29 08:45:57', '2026-04-29 08:46:04', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_4439988176781229808', '人工智能', '“擎天租”完成数亿元Pre-A轮融资', 'https://36kr.com/newsflashes/3787289802939395?f=rss', '36kr', '2026-04-29', '4月29日，“擎天租”宣布完成数亿元Pre-A轮融资。本轮投资方包括正大集团旗下正大机器人、长信股份等产业方，美格智能、蓝思科技等多家上市公司参与，老股东明嘉资本、知行投资和睿资创投超额认购。融资资金将主要用于全国履约服务网络建设、机器人资产与调度系统升级、物流保险体系完善、标准化场景产品打磨及全球化服务网络拓展。', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 10:55:06', '2026-04-29 10:55:05', '2026-04-29 10:55:25', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_4492122964539566238', '人工智能', '成大生物在上海成立医药科技新公司', 'https://36kr.com/newsflashes/3787272147016969?f=rss', '36kr', '2026-04-29', '36氪获悉，爱企查App显示，近日，上海成大致远医药科技有限公司成立，法定代表人为李业基，注册资本10亿元人民币，经营范围包括人工智能理论与算法软件开发、人工智能基础软件开发、人工智能应用软件开发、人工智能双创服务平台等。股东信息显示，该公司由辽宁成大生物股份有限公司全资持股。', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 10:55:06', '2026-04-29 10:55:05', '2026-04-29 10:55:05', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_4556956383352550099', '新能源汽车', '恒指开盘涨0.63%，恒生科技指数涨1.07%', 'https://36kr.com/newsflashes/3787224093023490?f=rss', '36kr', '2026-04-29', '36氪获悉，恒指开盘涨0.63%，恒生科技指数涨1.07%；科技、汽车股走强，蔚来、京东健康涨超4%，理想汽车涨超3%，小鹏集团、哔哩哔哩涨超2%；有色金属、煤炭板块调整，五矿资源、中煤能源跌超1%；新股商米科技高开292.20%。', '该事件值得关注。', 'other', 0.5, '2026-04-29 09:24:23', '2026-04-29 09:24:22', '2026-04-29 09:24:22', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_4643805612850612136', '半导体', '「寻明生科」完成3500万美元A+轮融资，首个抗体药物即将进入临床｜36氪首发', 'https://36kr.com/p/3784480103455748?f=rss', '36kr', '2026-04-28', '文｜胡香赟\n  编辑｜海若镜\n  36氪获悉，寻明生科（Aureka Biotechnologies）近期已完成3500万美元A+轮融资。本轮融资由红杉中国领投，经纬创投、博远资本跟投，老股东五源资本、启明创投、纽尔利资本等持续加注。\n  去年底，寻明生科就曾获得一笔数千万美元的A轮融资。截至目前，公司A轮次融资的累计金额已接近1亿美元。\n  寻明生科方面表示，本轮募集资金将用于推动自研创新功能抗', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 10:16:48', '2026-04-29 10:16:47', '2026-04-29 10:16:59', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_4767327415361838758', '人工智能', '氪星晚报｜我国最大规模AI4S集群接入全国一体化算力网；亚马逊低地轨道卫星计划又一批卫星发射升空；我国首款正向设计自转旋翼机完成首飞', 'https://36kr.com/p/3786324189027332?f=rss', '36kr', '2026-04-28', '大公司：\n  拒买新闻就交税，澳洲拟向科技巨头征约2%营收税\n  澳大利亚政府公布法案草案，拟对Meta、谷歌等科技巨头征收新税，除非这些平台自愿与当地新闻机构签署付费协议，以应对传统媒体在数码平台冲击下面临的生存压力。据报道，根据拟议的新法律安排，这些大型数码平台须就分享本地媒体新闻内容所带来的平台流量，向出版商提供经济补偿。澳洲总理阿尔巴尼斯表明，政府将给予Meta、谷歌等公司机会，与本地新闻', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:45:56', '2026-04-29 09:45:55', '2026-04-29 09:45:55', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_482443192283000807', '机器人', '风电产业链业绩分化，“两海”市场成胜负手', 'https://36kr.com/newsflashes/3787147629239555?f=rss', '36kr', '2026-04-29', '近日，风电产业链厂商2025年度业绩陆续出炉。过去一年，风电整机厂商营收普遍水涨船高，但利润分化明显。相比之下，齿轮箱、风电主轴、风电基础装备等上下游核心部件供应商业绩普遍高增长。总的来看，海外及海上“两海”业务占比高的厂商业绩要好于业务结构单一的厂商。因此，布局“两海”业务成为风电厂商共识。业内人士判断，海外和海上是中国风电产业发展的两个关键增量市场，其中，中国的海上风电已进入规模化开发阶段。（', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 08:43:30', '2026-04-29 08:43:29', '2026-04-29 08:43:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_4896345683683068763', '人工智能', '白宫据悉正在研讨恢复与Anthropic合作', 'https://36kr.com/newsflashes/3787275928411395?f=rss', '36kr', '2026-04-29', '据知情人士透露，白宫正在制定指导方针，允许各机构绕过对Anthropic的供应链风险的认定，并引入包括其迄今为止最强大的Mythos在内的新模型。两位消息人士称，目前正在起草的一项行政命令草案，除其他与政府使用人工智能相关的措施外，可能还会为政府提供一种缓和与Anthropic公司对抗的途径。（新浪财经）', '该事件值得关注。', 'other', 0.5, '2026-04-29 10:23:50', '2026-04-29 10:23:50', '2026-04-29 10:24:11', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_5210358311442655731', '人工智能', '36氪首发 | 韩国现代、微光创投押注焊接机器人，营收预计破数亿，拿下船厂数千万订单', 'https://36kr.com/p/3785955616152839?f=rss', '36kr', '2026-04-28', '作者丨欧雪\n  编辑丨袁斯来\n  硬氪获悉，专注于焊接垂直场景的具身智能机器人公司——昇视唯盛已完成数千万元A+轮融资。本轮融资由韩国现代、微光创投联合投资，资金将主要用于“具身大脑”的研发、软硬件产品的迭代以及市场推广。\n  昇视唯盛成立于2020年，核心团队由来自哈尔滨工业大学、上海交通大学等高校的机器人领域专家，以及拥有多年工业自动化从业经验的资深人员组成。创始人王德钊及核心团队在机器人及自', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:33:14', '2026-04-29 09:33:14', '2026-04-29 09:33:14', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_5327531793169526286', '人工智能', '8点1氪丨百度废除字母职级标签；Meta被曝准备撤销对Manus收购；张雪称曾拒绝了半个亿的商务合作', 'https://36kr.com/p/3787150633065728?f=rss', '36kr', '2026-04-29', '今日热点导览\n  阿联酋宣布将退出欧佩克及“欧佩克+”\n  比亚迪宣布5月1日起涨价\n  五粮液：延期披露年报、一季报\n  普通本科高校上新38种专业\n  全马“破2”跑鞋被炒至近2万元\n  韩股市值超越英国，成为全球第八大股市\n  TOP3大新闻\n  百度职级体系大调整：字母标签改为5级至12级数字职级体系\n  4月28日，据《科创板日报》，百度发布全员信，通知职级体系大调整，其将中管层以下的专', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:45:56', '2026-04-29 09:45:55', '2026-04-29 09:45:55', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_5722095064365490496', '人工智能', '最前线｜爱芯元智仇肖莘：大算力芯片将成为企业明年的主要增长引擎', 'https://36kr.com/p/3784806758243587?f=rss', '36kr', '2026-04-27', '在汽车行业越来越强调降本的今天，车企心中的天平逐渐偏向了更具性价比的国产芯片。爱芯元智看到了这一发展机遇，北京车展前期，爱芯元智与千里科技、阶跃星辰等企业成立“千里联盟”，同时企业将于今年三季度发布M97这颗大算力辅助驾驶芯片。\n  爱芯元智创始人仇肖莘在北京车展上公开表示，“大算力产品已成功流片，正进入正常的开发周期”，2026年将逐步导入多款车型，成为业绩增长的重要引擎。目前，传统终端计算产品', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 08:43:23', '2026-04-29 08:43:22', '2026-04-29 08:43:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_5732641017056066091', '人工智能', '前米哈游高管创业，AI 原生增长 Agent LeapMind Growth 获 CMC 资本领投', 'https://36kr.com/p/3786123369094405?f=rss', '36kr', '2026-04-29', '\n  2026 年 4 月 29&nbsp;日，上海讯 ——AI 原生增长 Agent LeapMind Growth&nbsp;今日宣布完成天使 + 轮融资，由 CMC 资本领投。本轮融资将主要用于核心产品 GrowthGPT 的研发迭代、产研团队扩充及早期市场拓展。\n  LeapMind Growth 成立于 2025 年 4 月，由前米哈游全球用户增长负责人、前快手增长策略中心负责人马如平（', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 10:54:38', '2026-04-29 10:54:38', '2026-04-29 10:54:56', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_5772861886247985959', '新材料', '新政后首单“H转深A”诞生，越疆科技创业板IPO获受理', 'https://36kr.com/newsflashes/3787137966382341?f=rss', '36kr', '2026-04-29', '4月27日，深交所官网显示，深圳市越疆科技股份有限公司（简称“越疆科技”）的创业板IPO申请已获受理。资料显示，越疆科技已于2024年12月在港交所上市。2025年6月10日印发的《中共中央办公厅 国务院办公厅关于深入推进深圳综合改革试点深化改革创新扩大开放的意见》提到，允许在香港联合交易所上市的粤港澳大湾区企业，按照政策规定在深圳证券交易所上市。市场分析指出，伴随着越疆“回A”的推进，“H转深A', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 08:43:27', '2026-04-29 08:43:27', '2026-04-29 08:43:27', 0.5);
