INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_6397368609152023375', '半导体', '「寻明生科」完成3500万美元A+轮融资，首个抗体药物即将进入临床｜36氪首发', 'https://36kr.com/p/3784480103455748?f=rss', '36kr', '2026-04-28', '文｜胡香赟\n  编辑｜海若镜\n  36氪获悉，寻明生科（Aureka Biotechnologies）近期已完成3500万美元A+轮融资。本轮融资由红杉中国领投，经纬创投、博远资本跟投，老股东五源资本、启明创投、纽尔利资本等持续加注。\n  去年底，寻明生科就曾获得一笔数千万美元的A轮融资。截至目前，公司A轮次融资的累计金额已接近1亿美元。\n  寻明生科方面表示，本轮募集资金将用于推动自研创新功能抗', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 10:55:17', '2026-04-29 10:55:17', '2026-04-29 10:55:17', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_6681218031527781626', '人工智能', '独家对谈｜兴辉时代创始人高兴辉，90后小镇女孩离开教培大厂，三年创造2亿GMV的倔强人生', 'https://36kr.com/p/3786265971334150?f=rss', '36kr', '2026-04-29', '\n  图源：公众号「职场Bonus」（ID：ZhiChangHongLi）\n  兴辉，山西人，三次面试新东方才被录用。\n  转战高途教育后，她与另外三名男同事一同被封为公司的“三王一后”。\n  如今她已自己创业近三年。带着对教培行业发展水温的好奇，我们拜访了兴辉的公司。\n  一进门，同事们喊她“辉哥”——这与她外表精瘦，笑起来有虎牙的形象相比，实在让人难以关联。\n  但当我们听到在整个教培行业最为', '人事变动可能影响公司战略方向。', 'person', 0.5, '2026-04-29 09:33:14', '2026-04-29 09:33:13', '2026-04-29 09:33:13', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_6761046346652777345', '人工智能', '8点1氪丨百度废除字母职级标签；Meta被曝准备撤销对Manus收购；张雪称曾拒绝了半个亿的商务合作', 'https://36kr.com/p/3787150633065728?f=rss', '36kr', '2026-04-29', '今日热点导览\n  阿联酋宣布将退出欧佩克及“欧佩克+”\n  比亚迪宣布5月1日起涨价\n  五粮液：延期披露年报、一季报\n  普通本科高校上新38种专业\n  全马“破2”跑鞋被炒至近2万元\n  韩股市值超越英国，成为全球第八大股市\n  TOP3大新闻\n  百度职级体系大调整：字母标签改为5级至12级数字职级体系\n  4月28日，据《科创板日报》，百度发布全员信，通知职级体系大调整，其将中管层以下的专', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 09:24:27', 0.5);
