INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_7433769929528154354', '半导体', '「寻明生科」完成3500万美元A+轮融资，首个抗体药物即将进入临床｜36氪首发', 'https://36kr.com/p/3784480103455748?f=rss', '36kr', '2026-04-28', '文｜胡香赟\n  编辑｜海若镜\n  36氪获悉，寻明生科（Aureka Biotechnologies）近期已完成3500万美元A+轮融资。本轮融资由红杉中国领投，经纬创投、博远资本跟投，老股东五源资本、启明创投、纽尔利资本等持续加注。\n  去年底，寻明生科就曾获得一笔数千万美元的A轮融资。截至目前，公司A轮次融资的累计金额已接近1亿美元。\n  寻明生科方面表示，本轮募集资金将用于推动自研创新功能抗', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 10:23:58', '2026-04-29 10:23:58', '2026-04-29 10:23:58', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_7453786871208992408', '人工智能', '2025年我国全年词元累计调用量达21100万亿，日均调用量呈指数级增长', 'https://36kr.com/newsflashes/3787291440831488?f=rss', '36kr', '2026-04-29', '今天，《全国数据资源调查报告（2025年）》在第九届数字中国建设峰会上发布，报告显示，我国数据资源正以更大力度，赋能人工智能创新发展。“词元”（Token），是人工智能大模型为了高效处理数据，把数据进行拆分后的最小信息单元。2025年，全国日均词元调用量从年初的超万亿增长到年末的100万亿，呈现指数级增长；全年词元累计调用量达到约21100万亿。（央视新闻）', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 10:55:05', '2026-04-29 10:55:05', '2026-04-29 10:55:23', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_7490817329422474357', '人工智能', '比博斯特完成超10亿元B轮融资，智能底盘三轴产品全覆盖｜36氪独家', 'https://36kr.com/p/3740907027054600?f=rss', '36kr', '2026-04-29', '36氪独家获悉，智能底盘企业比博斯特近日完成B+轮融资，由浙江省新能源汽车产业基金领投，顺创产投、杭资直投基金等联合投资。企业B+轮融资超7亿元，B轮系列融资总额已超10亿元。本轮融资将用于已有产品的规模化增长及前沿产品的开发。\n  比博斯特成立于2021年，其股东不仅包括主机厂蔚来，还涵盖恒隆、保隆等汽车底盘供应链头部企业。2025年，曾在底盘巨头采埃孚担任高管的巫子平、郁炜陆续加入比博斯特，出', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:45:56', '2026-04-29 09:45:55', '2026-04-29 09:45:55', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_751926871078813291', '新能源汽车', '恒指开盘涨0.63%，恒生科技指数涨1.07%', 'https://36kr.com/newsflashes/3787224093023490?f=rss', '36kr', '2026-04-29', '36氪获悉，恒指开盘涨0.63%，恒生科技指数涨1.07%；科技、汽车股走强，蔚来、京东健康涨超4%，理想汽车涨超3%，小鹏集团、哔哩哔哩涨超2%；有色金属、煤炭板块调整，五矿资源、中煤能源跌超1%；新股商米科技高开292.20%。', '该事件值得关注。', 'other', 0.5, '2026-04-29 10:24:08', '2026-04-29 10:24:08', '2026-04-29 10:24:08', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_7526959990648722773', '人工智能', '独家对谈｜缘启智慧CEO邓江，一个80后银行码农出身的AI医疗创业者', 'https://36kr.com/p/3786252394945795?f=rss', '36kr', '2026-04-28', '\n  图源：公众号「职场Bonus」（ID：ZhiChangHongLi）\n  今年三月，《职场Bonus》报道了前百川智能商业化合伙人邓江加入北电数智</', '该事件值得关注。', 'other', 0.5, '2026-04-29 09:45:56', '2026-04-29 09:45:55', '2026-04-29 09:45:55', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_7760823319179961567', '人工智能', '比博斯特完成超10亿元B轮融资，智能底盘三轴产品全覆盖｜36氪独家', 'https://36kr.com/p/3740907027054600?f=rss', '36kr', '2026-04-29', '36氪独家获悉，智能底盘企业比博斯特近日完成B+轮融资，由浙江省新能源汽车产业基金领投，顺创产投、杭资直投基金等联合投资。企业B+轮融资超7亿元，B轮系列融资总额已超10亿元。本轮融资将用于已有产品的规模化增长及前沿产品的开发。\n  比博斯特成立于2021年，其股东不仅包括主机厂蔚来，还涵盖恒隆、保隆等汽车底盘供应链头部企业。2025年，曾在底盘巨头采埃孚担任高管的巫子平、郁炜陆续加入比博斯特，出', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:55:05', '2026-04-29 10:55:05', '2026-04-29 10:55:25', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_7800144772784241066', '人工智能', '8点1氪：中方禁止外资收购Manus；上海迪士尼回应游客吸烟冲突事件；泡泡玛特LABUBU 冰箱未发售已溢价3000元', 'https://36kr.com/p/3785730095127817?f=rss', '36kr', '2026-04-28', 'TOP3大新闻\n  DeepSeek 输入缓存降价\n  多家美国廉价航空公司寻求政府资金纾困\n  东方甄选回应大量用户申请退会员\n  穿西装开空调太费电，日本东京鼓励公务员穿短裤\n  印度移动支付平台MobiKwik获央行批准\n  TOP3大事件\n  国家发展改革委：依法依规对外资收购Manus项目作出禁止投资决定\n  据国家发展改革委网站4月27日消息，外商投资安全审查工作机制办公室（国家发展改', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:45:56', '2026-04-29 09:45:55', '2026-04-29 09:45:55', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_7881774048367862603', '人工智能', '期货市场交投活跃，上市期货公司首季盈利集体倍增', 'https://36kr.com/newsflashes/3787146901429504?f=rss', '36kr', '2026-04-29', '截至4月28日晚，4家A股主板上市期货公司悉数披露2025年年报与2026年一季报。从财务数据看，期货行业去年以来的盈利改善趋势较为明显，尤其是今年一季度呈现业绩爆发式增长，4家公司一季度归母净利润均倍增，同比增幅在138%至939%不等。 业内人士表示，一季度地缘政治风险持续发酵，带动能源化工、有色金属等大宗商品价格剧烈波动，期货市场成交规模同步增长，是推动期货行业盈利向好的主要原因。从行业角度', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 08:43:23', '2026-04-29 08:43:22', '2026-04-29 08:43:29', 0.5);
