INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_808601860207127059', '人工智能', '成大生物在上海成立医药科技新公司', 'https://36kr.com/newsflashes/3787272147016969?f=rss', '36kr', '2026-04-29', '36氪获悉，爱企查App显示，近日，上海成大致远医药科技有限公司成立，法定代表人为李业基，注册资本10亿元人民币，经营范围包括人工智能理论与算法软件开发、人工智能基础软件开发、人工智能应用软件开发、人工智能双创服务平台等。股东信息显示，该公司由辽宁成大生物股份有限公司全资持股。', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 10:54:38', '2026-04-29 10:54:38', '2026-04-29 10:54:59', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_8307510117735866210', '人工智能', '前米哈游高管创业，AI 原生增长 Agent LeapMind Growth 获 CMC 资本领投', 'https://36kr.com/p/3786123369094405?f=rss', '36kr', '2026-04-29', '\n  2026 年 4 月 29&nbsp;日，上海讯 ——AI 原生增长 Agent LeapMind Growth&nbsp;今日宣布完成天使 + 轮融资，由 CMC 资本领投。本轮融资将主要用于核心产品 GrowthGPT 的研发迭代、产研团队扩充及早期市场拓展。\n  LeapMind Growth 成立于 2025 年 4 月，由前米哈游全球用户增长负责人、前快手增长策略中心负责人马如平（', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 10:16:39', '2026-04-29 10:16:38', '2026-04-29 10:16:56', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_8360099428974227423', '半导体', '可回收火箭密集验证窗口开启，商业航天产业链有望迈入规模化量产元年', 'https://36kr.com/newsflashes/3787190594558981?f=rss', '36kr', '2026-04-29', '4月下旬，中国商业航天迎来可回收火箭密集验证窗口。长征十号乙、朱雀三号等多型火箭接连实施回收技术验证，国家《商业航天标准体系（1.0版）》同步落地。在产业政策与核心技术共振之下，A股产业链公司一季报业绩兑现亮眼。Wind数据显示，万得商业航天概念指数近期表现不俗，4月7日以来累计上涨6.51%。分析人士认为，可回收技术的工程化落地将推动发射成本指数级下降，叠加政策标准体系的顶层引导，商业航天正从技', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:24:17', '2026-04-29 09:24:17', '2026-04-29 09:24:17', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_8548538073339306879', '人工智能', 'OpenAI和Anthropic就高阶网络安全AI模型与美国众议院委员会展开会晤', 'https://36kr.com/newsflashes/3787141617490945?f=rss', '36kr', '2026-04-29', 'OpenAI与Anthropic向美国众议院国土安全委员会工作人员，专项汇报了旗下具备网络攻防能力的新一代AI模型，以及该类技术对网络安全产生的各类影响。这是美国立法机构首次就新型AI模型引发的网络威胁，与两大AI巨头开展专项沟通的会议之一，重点涵盖防护薄弱的关键基础设施领域面临的安全风险。委员会一名助理证实，两家企业于上周四，以两场独立非公开机密会议形式，向国会工作人员进行专项简报。（新浪财经）', '技术突破可能带来新的商业机会。', 'tech', 0.5, '2026-04-29 08:45:58', '2026-04-29 08:45:57', '2026-04-29 08:46:04', 0.5);
