INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/723.htm', '半导体', '立讯精密 2026 年净利润 78.40 亿元 ~81.06 亿元，同比预增 18%~22%', 'https://www.ithome.com/0/944/723.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 28 日消息，立讯精密今日发布 2026 年业绩预告报告：归母净利润：784024.10 万元 ~810601.19 万元，同比预增 18.00%~22.00%扣非净利润：625670.32 万元 ~672247.41 万元，同比预增 11.74%~20.06%基本每股收益：1.07 元 / 股 ~1.11 元 / 股', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 09:24:18', '2026-04-29 09:24:17', '2026-04-29 09:46:44', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/728.htm', '新能源汽车', '加速你的创意落地：Claude AI 接入 Adobe、Blender 等创意软件生态', 'https://www.ithome.com/0/944/728.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 29 日消息，Anthropic 今天（4 月 29 日）宣布升级 Claude，面向创意人士新增多款专属连接器（connectors），全面接入 Adobe、Blender 等八大创意软件生态，将 AI 能力深度整合至创意专业工作流中。IT之家援引博文介绍，此次更新帮助设计师和音乐制作人突破传统操作限制，支持 Ableton、Adobe、Affinity、Autodesk Fu', '技术突破可能带来新的商业机会。', 'tech', 0.5, '2026-04-29 09:33:26', '2026-04-29 09:33:26', '2026-04-29 09:46:51', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/729.htm', '半导体', '《永恒轮回》腾讯 WeGame 服 6 月 30 日停运，玩家数据可迁移至 Steam 版本', 'https://www.ithome.com/0/944/729.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 29 日消息，二次元大逃杀 MOBA 游戏《永恒轮回》发布公告，宣布 WeGame 服务器将于 2026 年 6 月 30 日正式停止运营。运营团队强调，《永恒轮回》国服并未停运，Steam 版本将继续正常运营，并与国内合作伙伴共同推进后续赛季内容、线下活动及赛事计划。根据公告，WeGame 服停运的主要原因是该版本作为独立运营服务器，当前用户活跃度难以维持健康可持续的运营状态，', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 09:24:18', '2026-04-29 09:24:17', '2026-04-29 09:46:51', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/731.htm', '人工智能', '继马里欧、银河之后，任天堂与照明娱乐合作的“第三部电影”确认 2028 年 4 月上映', 'https://www.ithome.com/0/944/731.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 29 日消息，《超级马里欧银河大电影》已于 4 月 3 日上映，目前豆瓣评分 7.0，IMDB 评分 6.4。VGC 发现，环球影业西班牙官网已经公布了任天堂与照明娱乐的第三部合作电影。环球影业官网显示，这部“未命名的照明娱乐 / 任天堂合作电影（2028 年 4 月）”项目上映日期为 2028 年 4 月 12 日。VGC 猜测，这既可能是《银河大电影》之后的又一部《超级马里欧', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:33:35', '2026-04-29 09:33:35', '2026-04-29 09:46:38', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/733.htm', '机器人', '消息称苹果 AirPods 将迎史诗级加强，iOS 27 全面重构 Siri AI 语音交互', 'https://www.ithome.com/0/944/733.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 29 日消息，科技媒体 9to5Mac 昨日（4 月 28 日）发布博文，报道称在 iOS 27 系统中，苹果公司将会全面重构 Siri 语音助手，从而增强 AirPods 耳机的交互体验，让其成为用户的全天候智能伴侣，实现类似电影《Her》中的无缝语音交互。IT之家援引博文介绍，基于目前掌握的信息，苹果 iOS 27 版 Siri 预估会提供以下功能：类似 ChatGPT 的对', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:33:29', '2026-04-29 09:33:28', '2026-04-29 09:46:51', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/734.htm', '新材料', 'IT早报 0429：央视解读“中方禁止 Manus 并购案”；“探店网红”白冰偷税被追罚 1891 万元；追觅 CEO 俞浩再轰小红书“算法问题”；张雪就声援华为余承东争议进行回应...', 'https://www.ithome.com/0/944/734.htm', 'IT之家', '2026-04-28', '“IT早报”时间，大家好，现在是 2026 年 4 月 29 日星期三，今天的重要科技资讯有：1、央视解读“中方禁止 Manus 并购案”：禁的是企业“洗澡式出海”2025 年 12 月，Meta 高调宣布以约 20 亿美元收购 Manus。作为一家依靠中国工程师和基础设施环境发展起来的 AI 公司，Manus 在获得美国投资后突然与中国元素进行“切割”，引发争议。&gt;&gt; 查看详情2、税', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:24:20', '2026-04-29 09:24:19', '2026-04-29 10:16:50', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/735.htm', '人工智能', '消息称苹果 iOS 27 将扩展 AI 修图功能，新增 3 项编辑功能', 'https://www.ithome.com/0/944/735.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 29 日消息，彭博社今天（4 月 29 日）发布博文，爆料称在 6 月 8 日开幕的 WWDC26 全球开发者大会上，苹果公司将会为 iOS 27 系统，引入三大 AI 照片编辑功能。彭博社称在 iOS 27 系统中，苹果公司将重点发力 AI 图像处理，帮助用户在几秒钟内快速优化、扩展和重构图像，引入 3 项 AI 编辑功能。在界面方面，新版照片（Photos）应用将新增“App', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 10:24:47', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/736.htm', '半导体', '漫步者发布严正声明：有不法分子篡改公司的媒体发布内容，制作并传播涉嫌污损伟人形象的伪造图片', 'https://www.ithome.com/0/944/736.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 29 日消息，漫步者官方微博昨晚发布严正声明，称发现有不法分子在社交平台及网络社群中，恶意篡改公司的媒体发布内容，制作并传播涉嫌污损伟人形象的伪造图片。漫步者微博配图显示，其已就此事向网络违法犯罪信息举报网站进行了举报。IT之家附漫步者声明原文如下：近日，我司发现有不法分子在社交平台及网络社群中，恶意篡改我司的媒体发布内容，制作并传播涉嫌污损伟人形象的伪造图片，同时捏造不实信息误', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:24:18', '2026-04-29 09:24:17', '2026-04-29 10:24:51', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/737.htm', '机器人', '马斯克庭审自述：创办公司只为拯救人类，OpenAI 奥尔特曼正掏空美国慈善根基', 'https://www.ithome.com/0/944/737.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 29 日消息，埃隆 · 马斯克与 OpenAI 联合创始人、现任 CEO 萨姆 · 奥尔特曼之间备受关注的庭审已于当地时间周一开庭，马斯克在证人席上将自己定位为“人类的拯救者”。他详细回顾了自己的成长经历，从在南非长大、只带着 2500 美元（IT之家注：现汇率约合 17087 元人民币）旅行支票和一袋衣服到加拿大上大学，再到后来创办 Zip2、PayPal 以及如今运营着的一系', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 09:24:25', '2026-04-29 09:24:25', '2026-04-29 10:24:51', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/738.htm', '半导体', '突破 2 纳米工艺极限：DNA 生物晶体管实现分子级计算与存储双重突破', 'https://www.ithome.com/0/944/738.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 29 日消息，韩国科学技术院（KAIST）于 4 月 22 日发布博文，宣布其工程生物学研究生院崔英宰（Yeongjae Choi）教授领导的团队突破 2 纳米工艺极限，成功研发出一种基于 DNA 的生物晶体管，实现了分子层面的计算与信息存储双重功能。相关研究成果已发表于国际期刊《Science Advances》。IT之家援引博文介绍，随着半导体技术逼近 2 纳米极限，进一步微', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:24:17', '2026-04-29 09:24:17', '2026-04-29 10:24:54', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/739.htm', '人工智能', '英伟达推出 Nemotron 3 Nano Omni 模型：采用 30B‑A3B 混合 MoE 架构，吞吐量最高提升 9.2 倍', 'https://www.ithome.com/0/944/739.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 29 日消息，当地时间 4 月 28 日，英伟达宣布推出名为 Nemotron 3 Nano Omni 的开源全模态推理模型，旨在为企业级 AI Agent 提供一体化基础模型底座。据介绍，这是一款将视频、音频、图像和文本的统一多模态推理集成于单个高效开放模型中的产品。该模型旨在替代智能体系统中常见的碎片化视觉-语音-语言模型链，从而减少推理跳数与编排复杂度，降低推理成本，同时增', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 10:24:37', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/741.htm', '机器人', '《连线》称苹果 2024 年斥资 120 万美元，雇佣旧金山警察保护 3 家门店', 'https://www.ithome.com/0/944/741.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 29 日消息，《连线》（Wired）于 4 月 27 日发布博文，报道称苹果公司于 2024 年斥资超 120 万美元，通过第三方安保公司雇佣旧金山警察为其三家门店提供安保。报道指出苹果公司在 2024 年支付超过 120 万美元（IT之家注：现汇率约合 820.2 万元人民币），通过安保供应商 Security Industry Specialists，为旧金山的三家 Appl', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:24:25', '2026-04-29 09:24:25', '2026-04-29 10:24:51', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/743.htm', '半导体', '苹果已修复天气应用服务异常，影响约 3 小时 45 分钟', 'https://www.ithome.com/0/944/743.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 29 日消息，根据苹果官方系统状态页面信息，苹果天气应用（Apple Weather）于昨晚出现宕机情况，部分用户遭遇数据加载缓慢或完全失效情况，持续约 3 小时 45 分钟，目前故障已经修复。在故障期间，用户发现该应用无法正常加载天气数据。根据苹果官方系统状态页面信息，本次服务中断于北京时间 4 月 28 日晚上 10 点 45 分钟开始，到 29 日凌晨 2 点 30 分修复', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:24:17', '2026-04-29 09:24:17', '2026-04-29 10:56:22', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/744.htm', '人工智能', '华为 Pura 90 Pro / Pro Max 手机开售：首发麒麟 9030S 芯片，售价 5499 元起', 'https://www.ithome.com/0/944/744.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，今天上午 10:08，华为 Pura 90 Pro / Pro Max 系列手机将正式开售。两款新机首发麒麟 9030S 处理器，售价 5499 元起。Pura 90 Pro12GB+256GB 售价 5499 元12GB+512GB 售价 5999 元16GB+512GB 售价 6499 元16GB+1TB 售价 7499 元<di', '技术突破可能带来新的商业机会。', 'tech', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/745.htm', '人工智能', 'iPad 版 AI 浏览器 Comet 上线，适配苹果 iPadOS 多任务处理', 'https://www.ithome.com/0/944/745.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，Perplexity 旗下 AI 浏览器 Comet 今天官宣全面适配苹果 iPadOS。新版本不仅引入多窗口浏览与多任务处理功能，还深度整合 OpenAI 与 Anthropic 等主流 AI 模型。Comet 浏览器在提供传统的网页浏览功能外，还深度整合了 AI 聊天机器人，支持调用 OpenAI、Anthropic 等主流 AI 模型，为用户提供智能化的搜索与', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/746.htm', '半导体', '微软 PowerToys 0.99 发布：任意位置拖动或缩放窗口、在系统托盘直接调整亮度对比度、加速 WinUI 3 迁移以贴近 Win11 现代化外观', 'https://www.ithome.com/0/944/746.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，微软昨晚发布了最新的 PowerToys 0.99 版本。感兴趣的用户可通过微软商店或 GitHub 下载，也可直接在 PowerToys 内检查更新。PowerToys 0.99 带来了两项全新预览功能：Grab And Move（抓取并移动）与 Power Display（显示器控制），同时命令面板（Command Palette）、Dock 等多项实用功能获得', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:24:17', '2026-04-29 09:24:17', '2026-04-29 10:56:22', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/747.htm', '半导体', '中国专门为动物建 240 米长桥，可保障斑林狸、豹猫等本土物种的迁徙不受运河阻隔', 'https://www.ithome.com/0/944/747.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，据央视新闻今日报道，随着在广西的子材大桥昨日正式通车，平陆运河 27 座跨运河桥梁建成。值得一提的是，27 座桥中有一座专门为动物建的通道桥。桥长 240.2 米、宽 20 米，主要为保障斑林狸、豹猫等本土物种的迁徙不受运河阻隔。桥上还会布置植物，模拟动物的生活环境，引导动物通行。IT之家查询获悉，平陆运河是新中国成立', '该事件值得关注。', 'other', 0.5, '2026-04-29 09:24:17', '2026-04-29 09:24:17', '2026-04-29 10:56:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/750.htm', '新能源汽车', '安靠科技 2026 财年第一财季净利润 8300 万美元，同比增长 293.23%', 'https://www.ithome.com/0/944/750.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，Amkor（安靠科技）今日发布 2026 财年第一财季（也是第一季度）报告：营业总收入： 16.85 亿美元，同比增长 27%归母净利润： 8335.1 万美元，同比增长 294.50%经营现金流： 1.45 亿美元，同比增长 +500.80%基本每股收益： 0.34 美元 / 股，同比增长 277.78%稀释每股收益： 0.33 美元 / 股，同比增长 266.6', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 09:24:23', '2026-04-29 09:24:22', '2026-04-29 10:56:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/751.htm', '半导体', '部分第三方备份工具不兼容微软 Win11 四月更新，无法读取 / 挂载备份文件', 'https://www.ithome.com/0/944/751.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，科技媒体 BornCity 昨日（4 月 28 日）发布博文，报道称部分磁盘备份软件不兼容微软 Windows 11 四月更新，导致无法正常挂载备份文件。IT之家注：在 2026 年 4 月 14 日补丁星期二活动日，微软面向 Windows 11 系统推送累积更新（KB5083769，内部版本 26200.8246/26100.8246），多位用户反馈安装后，导致', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:24:17', '2026-04-29 09:24:17', '2026-04-29 10:56:22', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/753.htm', '人工智能', '小米米家中央空调人感风风管机大 4 匹开售：可变上下双出风，8999 元', 'https://www.ithome.com/0/944/753.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，小米米家中央空调人感风风管机大 4 匹双出风版本昨晚 20:00 正式开售，售价 8999 元，国补到手价 7649.15 元。这款空调为超一级能效（APF 4.62），外机大双排、内机大三排纯铜换热器，换热面积 +15%，支持 10 年免费包修；采用全新一代可变双出风风道，制冷制热双风路；人感智能科技可实现风吹人、风避人、人近柔风、人走节能等功能。<img cl', '该事件值得关注。', 'other', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/754.htm', '人工智能', '美国国防部确认与谷歌 AI 合作并暗讽 Anthropic：过度依赖单一供应商不是好事', 'https://www.ithome.com/0/944/754.htm', 'IT之家', '2026-04-29', '4 月 29 日，据 CNBC 报道，美国国防部 AI 负责人卡梅伦 · 斯坦利 (Cameron Stanley) 周二证实，美国国防部正扩大对谷歌 Gemini AI 模型的使用。就在大约两个月前，美国防部已将 Anthropic 列为供应链风险，并终止了与其合作。此前，知情人士透露，美国国防部正将谷歌最新模型用于机密项目。图注：谷歌 Gemini站 The Information 援引知情人', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/755.htm', '新能源汽车', '远程执行漏洞被 GitHub 紧急修复：1 条 git push 命令，可访问数百万代码库', 'https://www.ithome.com/0/944/755.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，安全机构 Wiz Research 昨日（4 月 28 日）发布博文，披露 GitHub 存在严重漏洞 CVE-2026-3854。攻击者仅需一条标准 git push 命令，即可触发远程代码执行，进而访问数百万公共和私有仓库。该漏洞追踪编号为 CVE-2026-3854，任何经过身份验证的用户只需执行标准的 git push 命令，就能在 GitHub 后端服务器', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:24:23', '2026-04-29 09:24:22', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/756.htm', '人工智能', '全新一代红旗 H9 汽车官图发布：中式宫殿礼序章法外观、首搭华为乾崑智驾 ADS 5', 'https://www.ithome.com/0/944/756.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，一汽红旗昨日放出了全新一代红旗 H9 的官图，展示了新车的外观细节和内饰设计。据介绍，全新一代红旗 H9 外观设计灵感取自中式宫殿的礼序章法，融自然山水的流转气韵。新车主打中式豪华美学，采用高山飞瀑格栅搭配贯穿式 U 型灯组设计，辅以四平八稳尾灯 + 镭射工艺。<img class=\"no-alt-img\" src=\"https://img.ithome.com/n', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 10:56:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/760.htm', '半导体', '福岛核事故 15 年后，日本野猪体内放射性铯仍检测超标', 'https://www.ithome.com/0/944/760.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，日本福岛县政府于 4 月 27 日公布了最新的野生鸟兽放射线监测调查结果。其中明确标注了二本松市和须贺川市捕获的野猪共 3 头，其体内放射性铯（铯-134 与铯-137）超过食品卫生法基准值（100 Bq / kg），具体数值未公布。据日本《福岛民报》4 月 28 日报道，此次野猪体内放射性物质检出的根源可追溯至 2011 年福岛第一核电站的核泄漏事故。受事故影响，', '该事件值得关注。', 'other', 0.5, '2026-04-29 09:24:17', '2026-04-29 09:24:17', '2026-04-29 10:56:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/761.htm', '人工智能', '开源鸿蒙 OpenHarmony 社区代码量突破 1.3 亿行，版本已迭代至 6.1 Release', 'https://www.ithome.com/0/944/761.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，在第九届数字中国建设峰会召开前夕，鸿蒙生态峰会（以下简称“峰会”）在福州海峡国际会展中心成功举办。开放原子开源基金会理事长谢少锋在致辞中分享了一组数据：开源鸿蒙自华为捐赠至开放原子开源基金会以来实现快速发展，社区代码量已突破 1.3 亿行，贡献者超过 13000 名，版本已迭代至 6.1 Release，支持手机、平板、电脑、电视、穿戴及行业智能终端等形态。目前，已', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 10:56:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/762.htm', '人工智能', '吉利银河 M7 上市 12 小时大定破 1 万台，限时 10.98 万元起', 'https://www.ithome.com/0/944/762.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，吉利银河官方今日宣布，吉利银河 M7 上市 12 小时大定破 1 万台。吉利银河 M7 昨晚正式上市，新车共推出 4 款配置车型，限时指导价下探至 10.98 万元起，IT之家附价格如下：车型官方指导价（万元）<stron', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 10:56:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/763.htm', '机器人', 'Framework 推出 RTX 5070 笔记本电脑 GPU 12GB 版本显卡模块，比 8GB 贵 70+%', 'https://www.ithome.com/0/944/763.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，NVIDIA（英伟达）北京时间昨晚推出了 GeForce RTX 5070 笔记本电脑 GPU 12GB 版本，模块化硬件制造商 Framework 也在官网上线了基于该新版本的显卡模块，预售价 1199 美元（IT之家注：现汇率约合 8209 元人民币）。IT之家注意到，Framework 同时也提供原版的 RTX 5070 笔记本电脑 GPU 显卡模块，现价 6', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:24:25', '2026-04-29 09:24:25', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/764.htm', '人工智能', '苹果 iPhone 印度扩产受阻，春节期间失去中国团队支持直接停摆', 'https://www.ithome.com/0/944/764.htm', 'IT之家', '2026-04-29', '北京时间 4 月 29 日，据《日经亚洲》报道，苹果希望实现生产的多元化，但是其供应链依旧高度依赖中国。虽然该公司对印度寄予厚望，但是没有中国团队的帮助，印度生产难以独立运作。iPhone 17 Pro报道称，苹果一直面临压力，需要实现供应链多元化以增强韧性，但这一过程漫长而复杂，将持续到其下一任 CEO 约翰 · 特努斯 (John Ternus) 的任期内。不过，苹果供应商及公司内部人士向《日', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 10:56:24', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/765.htm', '新能源汽车', '旺宏抓住三星退场窗口：补位入门级存储芯片，MLC NAND 收入 2026Q1 同比增长 382%', 'https://www.ithome.com/0/944/765.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，集邦咨询 Trendforce 昨日（4 月 28 日）发布博文，报道称三星退出 LPDDR4、LPDDR4X 和 MLC NAND 等存储业务后，旺宏电子（Macronix）等存储厂商获得补位机会。IT之家援引博文介绍，三星近期退出低端 NAND 和 DRAM 业务，把产能转向利润更高的 LPDDR5/X 与高端 NAND 市场。受此影响，入门级平台所需的 LPD', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:33:26', '2026-04-29 09:33:26', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/766.htm', '元宇宙', 'DCU《超级少女》确认引进内地：颓废拽姐开启星际之旅、原 DCEU 海王变“暴狼”，档期待定', 'https://www.ithome.com/0/944/766.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，DC 电影官方今日发布 DCU《超级少女》全新中字预告，并宣布本片将引进内地，档期待定（北美今年 6 月 26 日上映）。本片一大亮点就是原本在 DCEU 饰演海王的杰森・莫玛将饰演暴狼一角。IT之家注：DCU 即 DC Universe（DC 宇宙），2022 年起由詹姆斯・古恩、彼得・萨夫兰联袂打造的架空世界，涵盖电影、剧集、游', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:33:16', '2026-04-29 09:33:16', '2026-04-29 10:56:18', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/768.htm', '人工智能', '蚂蚁集团百灵大模型开源 Ling-2.6-flash，提供 BF16、FP8、INT4 等版本', 'https://www.ithome.com/0/944/768.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，蚂蚁集团旗下的百灵大模型今日宣布，Ling-2.6-flash 正式开源。同步提供 BF16、FP8、INT4 等多个版本，方便开发者根据不同硬件环境、推理成本和部署需求灵活选择。Ling-2.6-flash 是一款总参数量 104B、激活参数 7.4B 的 Instruct 模型，两周前以 Elephant Alpha 的匿名身份登陆 OpenRouter。官方表', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:33:14', '2026-04-29 09:33:13', '2026-04-29 10:56:15', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/769.htm', '人工智能', '昔日“彩电一哥”康佳 2025 年巨亏 125.82 亿元同比扩大 237.73%，将被实施退市风险警示', 'https://www.ithome.com/0/944/769.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，康佳集团股份有限公司 4 月 28 日晚发布了 2025 年年度报告：实现营业收入为 98.35 亿元，同比下降 11.51%；实现归属于上市公司股东的净利润为-125.82 亿元，同比下降 237.73%；经营活动产生的现金流量净额为 16.11 亿元，同比下降 1026%。2025 年业绩变动原', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 09:45:56', '2026-04-29 09:45:55', '2026-04-29 10:56:24', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/770.htm', '新能源汽车', '消息称三星为内置 Qi2 磁吸组件，将调整 Galaxy S27 系列手机后摄布局', 'https://www.ithome.com/0/944/770.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，消息源 yeux1122 于 4 月 27 日发布博文，报道称三星为了内置磁吸模块，将调整手机内部元件方案，进而会调整相机布局。消息称三星调整 Galaxy S27 系列调整相机布局的原因，并非出于外观设计考量，而是为了在机身内部腾出充足空间，内置磁吸线圈和磁铁阵列，从而完全兼容 Qi2 无线充电标准。对于三星消费者而言，可以获得类似苹果 MagSafe 的体验。用', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:46:07', '2026-04-29 09:46:07', '2026-04-29 10:56:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/772.htm', '新材料', '同德接管影驰在海外运营，国内市场尚无变动消息', 'https://www.ithome.com/0/944/772.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，综合外媒 Wccftech 报道和油管频道 TecLab 视频，NVIDIA AIC 合作伙伴影驰 (GALAX) 在海外市场的运营由其母公司同德 (Palit) 直接接管。同德就此表示：为了提升管理与运营效率，并应对 AI 时代带来的各类原材料供应短缺问题，同德集团认为有必要进一步整合所有资源，以增强实力并为客户提供更优质的支持。IT之家注意到，影驰在中国大陆与海', '该事件值得关注。', 'other', 0.5, '2026-04-29 09:46:05', '2026-04-29 09:46:05', '2026-04-29 10:56:24', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/778.htm', '人工智能', 'Take-Two CEO 暗示《黑色洛城 2》仍有希望，但原开发商早已倒闭', 'https://www.ithome.com/0/944/778.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，Take-Two CEO 施特劳斯 · 泽尔尼克（Strauss Zelnick）在拉斯维加斯首届 iicon 活动上表示，公司正在考虑为《黑色洛城》等其他沉寂 IP 推出续作的可能性，但暂无具体计划可对外公布。当被问及 Take-Two 是否计划对《黑色洛城》IP 做更多开发时，Zelnick 明确回答“是的”，但随即又补充道“谁也说不准”。“从广义上讲，我们正在', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 10:16:39', '2026-04-29 10:16:38', '2026-04-29 10:56:15', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/779.htm', '新材料', '华为 WATCH FIT 5 智能手表首销：首发腕上微运动、1.82 英寸 AMOLED 屏，1099 元起', 'https://www.ithome.com/0/944/779.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，除了 Pura 90 Pro 系列手机外，华为 WATCH FIT 5 智能手表今日也迎来首销。该表主打超轻薄大屏 + 腕上微运动 + 长续航，售价 1099 元起。风信紫 / 向新绿 / 韵律黑 / 悦动白（氟胶表带）：1099 元光织银（尼龙表带）：1199 元<a contenteditable=\"false\" href=\"https://u.jd.com/f', '该事件值得关注。', 'other', 0.5, '2026-04-29 10:16:50', '2026-04-29 10:16:50', '2026-04-29 10:56:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/785.htm', '新材料', '海盗船推出 ThermalProtect PCIe 5.1 600W 12V-2x6 线缆：内置高温断电保护机制', 'https://www.ithome.com/0/944/785.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，CORSAIR（海盗船）美国当地时间昨日宣布推出 ThermalProtect PCIe 5.1 600W 12V-2x6 线缆。这一产品在距端子 30mm 的线梳处集成了高温保护 (OTP) 模块，当其检测到不安全温度时 OTP 技术会立即启动，使显卡关机以防止任何潜在损坏。如果用户确认 OTP 激活，则应长按电源键直到关机，等待电脑冷却，检查线缆端子和显卡接口是', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 10:16:50', '2026-04-29 10:16:50', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/786.htm', '人工智能', '地平线创始人余凯：不做“内卷”要“外卷”，16 万的车必须能卖 19 万，客户开开心心掏钱', 'https://www.ithome.com/0/944/786.htm', 'IT之家', '2026-04-29', '4 月 28 日上午消息，2026 北京国际车展期间，面对汽车行业强内卷与强降本的双重挤压，地平线创始人余凯给出了一个反共识的答案：跳出包围圈，在外线作战。“如果是顺着传统当前的现状让你去玩，在车厂、供应商和用户之间其实是三输，大家都输。”余凯直言，同质化竞争下，价格压力传导至供应商，没有利润就无法开发有竞争力的技术，最终恶性的环境传递给消费者，“消费者能够享受到高性能、美轮美奂的产品吗？不会的。', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 10:16:39', '2026-04-29 10:16:38', '2026-04-29 10:56:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/788.htm', '人工智能', 'Proton 揭示谷歌美国用户平均广告价值：苹果 iPhone 用户价值是安卓的 2.7 倍', 'https://www.ithome.com/0/944/788.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，隐私服务商 Proton 昨日（4 月 28 日）发布报告，指出谷歌正根据人口统计数据，为几乎每位美国用户“明码标价”。数据显示美国用户平均年度广告价值为 1605 美元（IT之家注：现汇率约合 10988 元人民币）。该报告利用 2025 年的广告竞价数据，分析了超过 54000 个人口统计资料，精准测算出广告商为接触不同美国用户所支付的费用。研究发现谷歌为了精准', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 10:16:39', '2026-04-29 10:16:38', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/789.htm', '新能源汽车', '深蓝 S09 汽车开启 V5.2.0 版本 OTA 升级：支持哨兵模式自动开启等', 'https://www.ithome.com/0/944/789.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，深蓝汽车今日宣布，深蓝 S09 汽车 OTA 升级 V5.2.0 版本。IT之家附主要更新内容如下：驾驶辅助哨兵模式：（ADS Max 版）驻车后哨兵模式根据环境自动开启，可设置家 / 公司等地点免打扰；开启哨兵时收到 OTA 升级任务，车辆完成升级后将自动恢复后视辅助：新增可通过方向盘自定义按键或中控屏，一键开启后鱼眼摄像头，弹窗查看车后情况（ADS SE 版）<', '该事件值得关注。', 'other', 0.5, '2026-04-29 10:16:54', '2026-04-29 10:16:53', '2026-04-29 10:56:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/791.htm', '机器人', '小米米家无线吸尘器 4C 开售：170AW 吸力、75 分钟续航，国补价 799 元', 'https://www.ithome.com/0/944/791.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，小米旗下米家无线吸尘器 4C 今日正式开售，该产品提供 170AW 吸力，官方定价 940 元，叠加国补后 799 元。京东小米米家无线吸尘器 4C</sp', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 10:16:56', '2026-04-29 10:16:56', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/792.htm', '机器人', 'PS5-Linux 工具发布：PS5 变 Linux PC，解锁 3.5GHz CPU 与 2.23GHz GPU', 'https://www.ithome.com/0/944/792.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，科技媒体 NotebookCheck 今天（4 月 29 日）发布博文，报道称安全工程师 Andy Nguyen 发布 PS5-Linux 工具，扩展索尼 PlayStation 5 的应用边界，将这款游戏主机转化为功能完备的 Linux 游戏 PC。根据 GitHub 项目文档，PS5-Linux 利用虚拟机管理程序漏洞（已修复），来解锁主机硬件限制。用户在 PS', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 10:16:56', '2026-04-29 10:16:56', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/793.htm', '人工智能', '特斯拉用 V14 Lite 让 HW3 老车主体验 FSD 最新功能，后续扩展至更多国际市场', 'https://www.ithome.com/0/944/793.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，马斯克已经在特斯拉 2026 年第一季度财报电话会议上确认，Hardware 3 车辆将无法实现无监督 FSD 功能，但公司并未抛弃老车主。为弥补硬件上的差距，特斯拉官方宣布为 HW3 设计的 V14 Lite 将于 6 月底在美国推出。这是一个大规模软件更新，旨在为老款车型引入最新 FSD 功能。特斯拉官方今日确认，继美国推出后，他们也计划将 V14 Lite 扩', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:16:39', '2026-04-29 10:16:38', '2026-04-29 10:56:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/798.htm', '新材料', '华硕灵耀 14 Air 骁龙版开售：X2 Elite Extreme 处理器，48GB+1TB 售 13999 元', 'https://www.ithome.com/0/944/798.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，全新华硕灵耀 16 Air 骁龙版轻薄本宣布开售。该机提供了两个版本，IT之家汇总如下：高通骁龙 X2 Elite 处理器、16GB 内存、1TB 固态硬盘：11999 元。高通骁龙 X2 Elite Extreme 处理器、48GB 内存、1TB 固态硬盘：13999 元。', '该事件值得关注。', 'other', 0.5, '2026-04-29 10:24:04', '2026-04-29 10:24:04', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/800.htm', '新能源汽车', '我国稀土、钨、锡等 14 种矿产储量居世界第一位，新一轮找矿突破行动成果公布', 'https://www.ithome.com/0/944/800.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，据央视新闻今日报道，我国新一轮找矿突破战略行动取得一系列新突破，矿产资源家底进一步夯实，有力保障了国家能源资源安全。自然资源部表示，2021 年启动新一轮找矿突破战略行动以来，我国矿产资源储量大幅增长，新发现战略性矿产大中型矿产地（油气田）398 处，铜、金、钾盐等大宗矿产勘查取得一批历史性突破，锂、氦气、高纯石英等战略新兴矿产勘查实现跨越式发展，资源自主保障能力显', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:54:53', '2026-04-29 10:54:53', '2026-04-29 10:56:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/801.htm', '人工智能', '缺乏 XInput 兼容性，Steam Controller 手柄暂未适配 Xbox 游戏库', 'https://www.ithome.com/0/944/801.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，科技媒体 NotebookCheck 今天（4 月 29 日）发布博文，报道称 Steam Controller 游戏手柄依赖 Steam 生态，无法原生兼容 Xbox Game Pass 等第三方平台游戏。Valve 官宣将于北京时间 5 月 5 日凌晨 1 点发售 Steam Controller 游戏手柄，售价为 99 美元（IT之家注：现汇率约合 677.8', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 10:54:38', '2026-04-29 10:54:38', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/806.htm', '半导体', 'Anthropic Claude Code 大幅涨价：从预估每日 6 美元翻倍至 13 美元', 'https://www.ithome.com/0/944/806.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，据多个媒体报道，Anthropic 近期在没有发布公告的情况下，悄悄将其 Claude Code 的 token 成本翻倍。根据 Claude Code 官网的最新说明，“在企业部署中，每个开发者每个活跃日的平均成本约为 13 美元，90% 的用户每日成本低于 30 美元。每个开发者每月的成本约为 150-250 美元（现汇率约合 1027 - 1712 元人民币）', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:54:47', '2026-04-29 10:54:47', '2026-04-29 10:56:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/810.htm', '人工智能', '京东快递“小红箱”全国上线，手机碰一碰就能寄特产行李', 'https://www.ithome.com/0/944/810.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，京东快递今日宣布在全国 80 个文旅城市完成“小红箱”智能寄递设备部署，全面覆盖景区、酒店、交通枢纽等出行核心场景，通过将 NFC（近场通信）技术与快递服务融合，进一步升级“轻松行”服务，提升五一假期出行体验。据介绍，京东快递“小红箱”核心依托 NFC 技术，实现秒碰秒寄。游客只需打开手机 NFC 功能轻碰“小红箱”，便可快速完成领券、下单、寄件全流程操作，无需手动', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:54:38', '2026-04-29 10:54:38', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/811.htm', '人工智能', 'Valve 坦言受运输成本上涨影响，Steam Controller 手柄售价高于内部预期', 'https://www.ithome.com/0/944/811.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，在接受 Polygon 媒体采访时，Valve 硬件工程师史蒂夫 · 卡尔达利（Steve Cardinali）坦言，受内存短缺和物流成本攀升影响，因此决定提前发布 Steam Controller 游戏手柄。Valve 于 2025 年发布游戏手柄 Steam Controller、游戏 PC 主机 Steam Machine 和 VR 头显 Steam Fram', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:54:38', '2026-04-29 10:54:38', '2026-04-29 10:56:29', 0.5);
